.darma-loader-cssloaders-github-25 {
  display: inline-block;
  width: 82px;
  height: 10px;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--loader-color, #f59e0b) 25%, var(--loader-secondary-color, #fde68a) 25%, var(--loader-secondary-color, #fde68a) 50%, var(--loader-color, #f59e0b) 50%, var(--loader-color, #f59e0b) 75%, var(--loader-secondary-color, #fde68a) 75%);
  background-size: 32px 100%; animation: darma-loader-cssloaders-github-25-progressStripe 0.97s linear infinite;
}
@keyframes darma-loader-cssloaders-github-25-progressStripe { 0% { background-position: 0 0; } 100% { background-position: 32px 0; } }

